1	/**
2	 * Layerinfinite — lib/scoring.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * 6-Factor Composite Scoring Engine
5	 * ══════════════════════════════════════════════════════════════
6	 *
7	 * FORMULA:
8	 *   composite_score = (
9	 *     w_success  * weighted_success_rate  +
10	 *     w_conf     * confidence             +
11	 *     w_trend    * trend_factor           +
12	 *     w_salience * salience_factor        +
13	 *     w_recency  * recency_factor         +
14	 *     w_latency  * latency_factor
15	 *   )
16	 *
17	 * Weights sum to 1.0. All inputs are normalised to [0, 1].
18	 *
19	 * Salience = importance weight of this action (from database).
20	 * Cold-start (confidence < MIN_CONFIDENCE): returns institutional priors.
21	 *
22	 * IN-MEMORY CACHE (5 min TTL):
23	 *   One entry per (action_id, context_id, customer_id).
24	 *   Refreshed on scoring-engine cron or on-demand.
25	 *   Falls back to DB query on cache miss.
26	 */
27	
28	import { supabase, ActionScore } from './supabase.js';
29	
30	// ── Weights ──────────────────────────────────────────────────
31	const W_SUCCESS = 0.40;  // primary driver
32	const W_CONF = 0.20;  // uncertainty penalty
33	const W_TREND = 0.20;  // directional momentum
34	const W_SALIENCE = 0.10;  // action importance
35	const W_RECENCY = 0.05;  // freshness bonus
36	const W_LATENCY = 0.05;  // response-time quality signal
37	
38	// Bayesian (Laplace) smoothing priors for composite score calculation.
39	// Used in computeCompositeScore(): (successes + α) / (total + α + β).
40	// NOTE: These are NOT used in updateAgentTrust() (outcome-orchestrator.ts),
41	// which uses exponential smoothing independently.
42	export const PRIOR_ALPHA = 1.0;  // Laplace prior successes (neutral = 1)
43	export const PRIOR_BETA = 1.0;  // Laplace prior failures  (neutral = 1)
44	
45	// ── Thresholds ───────────────────────────────────────────────
46	const MIN_CONFIDENCE = 0.15;  // below this → cold-start fallback (was 0.30; lowered so 2+ outcomes can differentiate)
47	const ESCALATION_SCORE = 0.20;  // below this → escalate_human
48	const CACHE_TTL_MS = 5 * 60 * 1000;  // 5 minutes
49	// LRU eviction: 1000 entries × ~2KB avg = ~2MB max resident cache size.
50	// V8 Map preserves insertion order; oldest key = first key in iterator.
51	// At 1000 entries, single-deletion eviction keeps memory bounded without
52	// a full LRU linked list implementation.
53	const MAX_CACHE_ENTRIES = 1000;
54	const IPS_DECISION_CHUNK_SIZE = 50;
55	const CLUSTER_PRIOR_MAX_BLEND = 0.15;
56	const CLUSTER_PRIOR_LOW_SAMPLE_THRESHOLD = 10;
57	const CLUSTER_PRIOR_STRONG_SIGNAL_MIN_SAMPLES = 50;
58	
59	function withTimeout<T>(promise: Promise<T>, ms: number): Promise<T | null> {
60	    return Promise.race([
61	        promise,
62	        new Promise<null>((resolve) => setTimeout(() => resolve(null), ms)),
63	    ]) as Promise<T | null>;
64	}
65	
66	// ── In-Memory Score Cache ─────────────────────────────────────
67	interface CacheEntry {
68	    scores: ScoredAction[];
69	    expires_at: number;
70	}
71	
72	const scoreCache = new Map<string, CacheEntry>();
73	
74	// Evict expired entries every 5 minutes
75	const CLEANUP_INTERVAL_MS = 5 * 60_000;
76	setInterval(() => {
77	    const now = Date.now();
78	    let evicted = 0;
79	    for (const [key, entry] of scoreCache.entries()) {
80	        if (entry.expires_at < now) {
81	            scoreCache.delete(key);
82	            evicted++;
83	        }
84	    }
85	    if (evicted > 0) {
86	        console.info(`[cache-cleanup] Evicted ${evicted} expired entries from scoreCache`);
87	    }
88	}, CLEANUP_INTERVAL_MS).unref();
89	
90	setInterval(() => {
91	    if (scoreCache.size > 0 && process.env['NODE_ENV'] !== 'production') {
92	        console.debug(`[cache-size] scoreCache: ${scoreCache.size} entries`);
93	    }
94	}, 15 * 60_000).unref();
95	
96	function cacheKey(customerId: string, contextId: string): string {
97	    return `${customerId}:${contextId}`;
98	}
99	
100	/**
101	 * Call this after any successful outcome write for (customerId, contextId).
102	 * Ensures the next getScores() call fetches fresh data from mv_action_scores
103	 * instead of serving a cached cold-start fallback.
104	 */
105	export function invalidateCache(customerId?: string, contextId?: string): void {
106	    if (customerId && contextId) {
107	        scoreCache.delete(cacheKey(customerId, contextId));
108	    } else {
109	        scoreCache.clear();
110	    }
111	}
112	
113	/**
114	 * Returns the cached composite score for a specific action in a context.
115	 * Used by log-outcome.ts for salience sampling:
116	 *   if (score > 0.9 && success) → salience = 0.1 (sampled down)
117	 * Returns null on cache miss (caller defaults to salience=1.0).
118	 */
119	export function getCachedScore(
120	    actionId: string,
121	    contextId: string,
122	    customerId: string
123	): number | null {
124	    // Scan the cache for this customer+context
125	    const key = cacheKey(customerId, contextId);
126	    const cached = scoreCache.get(key);
127	    if (!cached || cached.expires_at <= Date.now()) return null;
128	
129	    const match = cached.scores.find(s => s.action_id === actionId);
130	    return match ? match.composite_score : null;
131	}
132	
133	// ── Scoring types ─────────────────────────────────────────────
134	export type TrendLabel = 'stable' | 'improving' | 'degrading' | 'critical';
135	
136	export function trendLabel(trendDelta: number | null): TrendLabel {
137	    if (trendDelta === null) return 'stable';
138	    if (trendDelta <= -0.15) return 'critical';
139	    if (trendDelta < -0.05) return 'degrading';
140	    if (trendDelta > 0.05) return 'improving';
141	    return 'stable';
142	}
143	
144	export interface ScoredAction {
145	    action_id: string;
146	    action_name: string;
147	    action_category: string;
148	    composite_score: number;
149	    confidence: number;
150	    trend_delta: number | null;
151	    trend: TrendLabel;
152	    total_attempts: number;
153	    is_cold_start: boolean;
154	    is_low_sample: boolean;
155	    recommendation: 'recommend' | 'neutral' | 'avoid' | 'escalate';
156	}
157	
158	export interface ScoringResult {
159	    ranked_actions: ScoredAction[];
160	    top_action: ScoredAction;
161	    should_escalate: boolean;
162	    cold_start: boolean;
163	    context_id: string;
164	    customer_id: string;
165	    view_refreshed_at: string | null;
166	    served_from_cache: boolean;
167	}
168	
169	interface IPSBatchRow {
170	    unchosen_action_id: string | null;
171	    counterfactual_est: number | null;
172	    ips_weight: number | null;
173	    created_at: string | null;
174	}
175	
176	interface ClusterPrior {
177	    successRate: number;
178	    totalAttempts: number;
179	}
180	
181	function percentile(sortedValues: number[], q: number): number | null {
182	    if (sortedValues.length === 0) return null;
183	    if (sortedValues.length === 1) return sortedValues[0] ?? null;
184	
185	    const clampedQ = Math.max(0, Math.min(1, q));
186	    const idx = (sortedValues.length - 1) * clampedQ;
187	    const lo = Math.floor(idx);
188	    const hi = Math.ceil(idx);
189	    if (lo === hi) return sortedValues[lo] ?? null;
190	
191	    const loVal = sortedValues[lo] ?? 0;
192	    const hiVal = sortedValues[hi] ?? loVal;
193	    const frac = idx - lo;
194	    return loVal + (hiVal - loVal) * frac;
195	}
196	
197	function computeContextLatencyBaselineP75(rows: ActionScore[]): number | null {
198	    const latencies = rows
199	        .map((row) => row.avg_response_ms)
200	        .filter((v): v is number => typeof v === 'number' && Number.isFinite(v) && v > 0)
201	        .sort((a, b) => a - b);
202	
203	    return percentile(latencies, 0.75);
204	}
205	
206	function computeLatencyFactor(avgResponseMs: number | null | undefined, p75ResponseMs: number | null): number {
207	    if (typeof avgResponseMs !== 'number' || !Number.isFinite(avgResponseMs) || avgResponseMs <= 0) {
208	        return 0.5;
209	    }
210	    if (typeof p75ResponseMs !== 'number' || !Number.isFinite(p75ResponseMs) || p75ResponseMs <= 0) {
211	        return 0.5;
212	    }
213	
214	    // ratio=1.0 => neutral 0.5; faster actions score above neutral, slower actions below.
215	    const ratio = avgResponseMs / p75ResponseMs;
216	    const clamped = Math.max(0, Math.min(2, ratio));
217	    return Math.max(0, Math.min(1, 1 - clamped / 2));
218	}
219	
220	async function batchFetchIPSSignals(
221	    actionIds: string[],
222	    customerId: string
223	): Promise<Map<string, number>> {
224	    const uniqueActionIds = [...new Set(actionIds.filter(Boolean))];
225	    if (uniqueActionIds.length === 0) return new Map<string, number>();
226	
227	    // Step 1: scope decisions to the tenant via agent ownership.
228	    const { data: decisions, error: decisionsError } = await supabase
229	        .from('fact_decisions')
230	        .select('id, dim_agents!inner(customer_id)')
231	        .eq('dim_agents.customer_id', customerId)
232	        .order('created_at', { ascending: false })
233	        .limit(200);
234	
235	    if (decisionsError) {
236	        console.warn('[scoring] IPS decision scope lookup failed:', decisionsError.message);
237	        return new Map<string, number>();
238	    }
239	
240	    const decisionIds = (decisions ?? []).map((d: any) => d.id).filter(Boolean);
241	    if (decisionIds.length === 0) return new Map<string, number>();
242	
243	    const chunks: string[][] = [];
244	    for (let i = 0; i < decisionIds.length; i += IPS_DECISION_CHUNK_SIZE) {
245	        chunks.push(decisionIds.slice(i, i + IPS_DECISION_CHUNK_SIZE));
246	    }
247	
248	    const chunkResults = await Promise.all(chunks.map(async (chunk, i) => {
249	        const { data, error } = await supabase
250	            .from('fact_outcome_counterfactuals')
251	            .select('unchosen_action_id, counterfactual_est, ips_weight, created_at')
252	            .in('decision_id', chunk)
253	            .in('unchosen_action_id', uniqueActionIds)
254	            .order('created_at', { ascending: false })
255	            .limit(5 * uniqueActionIds.length);
256	
257	        if (error) {
258	            console.warn(
259	                `[scoring] IPS batch query failed (chunk ${i}):`,
260	                error.message,
261	                '| chunk_size:',
262	                chunk.length,
263	                '| action_count:',
264	                uniqueActionIds.length
265	            );
266	            return [] as IPSBatchRow[];
267	        }
268	
269	        return (data ?? []) as IPSBatchRow[];
270	    }));
271	
272	    const deduped = new Map<string, IPSBatchRow>();
273	    for (const row of chunkResults.flat()) {
274	        if (!row.unchosen_action_id || !row.created_at) continue;
275	        const dedupeKey = `${row.unchosen_action_id}:${row.created_at}`;
276	        if (!deduped.has(dedupeKey)) {
277	            deduped.set(dedupeKey, row);
278	        }
279	    }
280	
281	    if (deduped.size === 0) return new Map<string, number>();
282	
283	    const grouped = new Map<string, IPSBatchRow[]>();
284	    for (const row of deduped.values()) {
285	        const actionId = row.unchosen_action_id;
286	        if (!actionId) continue;
287	        const existing = grouped.get(actionId) ?? [];
288	        existing.push(row);
289	        grouped.set(actionId, existing);
290	    }
291	
292	    const signals = new Map<string, number>();
293	    for (const actionId of uniqueActionIds) {
294	        const rows = (grouped.get(actionId) ?? [])
295	            .sort(
296	                (a, b) => new Date(b.created_at ?? 0).getTime() - new Date(a.created_at ?? 0).getTime()
297	            )
298	            .slice(0, 5);
299	
300	        if (rows.length === 0) continue;
301	
302	        const avgEstimate = rows.reduce((sum, r) => sum + (r.counterfactual_est ?? 0), 0) / rows.length;
303	        const avgWeight = rows.reduce((sum, r) => sum + (r.ips_weight ?? 0), 0) / rows.length;
304	        const blendedSignal = Math.max(0, Math.min(1, avgEstimate * avgWeight));
305	        signals.set(actionId, blendedSignal);
306	    }
307	
308	    return signals;
309	}
310	
311	// ── 6-Factor scoring formula ─────────────────────────────────
312	/**
313	 * @param contextMatch — cosine similarity from context-embed.ts.
314	 *   null means exact match (fallback) → treated as 1.0.
315	 */
316	export function computeCompositeScore(
317	    row: ActionScore,
318	    contextMatch: number | null = null,
319	    ipsSignal: number | null = null,
320	    p75ResponseMs: number | null = null,
321	): number {
322	    // Factor 1: Weighted success rate (primary)
323	    // Applied Bayesian smoothing (Laplace / Beta distribution prior):
324	    const rawSuccessRate = row.weighted_success_rate ?? row.raw_success_rate ?? 0;
325	    const n = row.total_attempts ?? 0;
326	
327	    // Bayesian smoothed rate:
328	    // (successes + alpha) / (total + alpha + beta)
329	    const f_success = (rawSuccessRate * n + PRIOR_ALPHA) / (n + PRIOR_ALPHA + PRIOR_BETA);
330	
331	    // Factor 2: Confidence (Wilson-style: n/(n+10))
332	    const f_conf = row.confidence ?? 0;
333	
334	    // Factor 3: Trend delta → normalised to [0,1]
335	    const rawTrend = row.trend_delta ?? 0;
336	    const f_trend = Math.max(0, Math.min(1, (rawTrend + 0.5)));
337	
338	    // Factor 4: Salience — use actual salience_score from fact_outcomes
339	    // if available on the row. Defaults to 1.0 (neutral) if not present.
340	    // mv_action_scores exposes avg_salience_score computed from fact_outcomes.
341	    // If the column is null (old rows), fall back to 1.0 so behaviour is
342	    // unchanged for existing data.
343	    const rawSalience = (row as any).avg_salience_score;
344	    const f_salience = (rawSalience !== null && rawSalience !== undefined)
345	        ? Math.max(0, Math.min(1, Number(rawSalience)))
346	        : 1.0;
347	
348	    // Factor 5: Recency — bonus if last outcome < 24h ago
349	    let f_recency = 0.5;  // neutral default
350	    if (row.last_outcome_at) {
351	        const ageHours = (Date.now() - new Date(row.last_outcome_at).getTime()) / 3_600_000;
352	        f_recency = Math.max(0, Math.min(1, 1 - (ageHours / 168)));  // decay over 7 days
353	    }
354	
355	    // Factor 6: Latency — compare action's avg response time to context baseline p75.
356	    const f_latency = computeLatencyFactor(row.avg_response_ms, p75ResponseMs);
357	
358	    // Context match factor: null → 1.0 (exact match assumed)
359	    const f_context = contextMatch ?? 1.0;
360	
361	    const baseScore = (
362	        W_SUCCESS * f_success +
363	        W_CONF * f_conf +
364	        W_TREND * f_trend +
365	        W_SALIENCE * f_salience +
366	        W_RECENCY * f_recency +
367	        W_LATENCY * f_latency
368	    );
369	
370	    const sampleCount = row.total_attempts ?? 0;
371	    if (sampleCount >= 20 || ipsSignal === null) {
372	        return Math.max(0, Math.min(1, baseScore * f_context));
373	    }
374	
375	    const blendWeight = Math.min(0.10, ((20 - sampleCount) / 20) * 0.10);
376	    const blended = baseScore * (1 - blendWeight) + ipsSignal * blendWeight;
377	
378	    // Final clamp: composite_score must ALWAYS be in [0, 1]
379	    return Math.max(0, Math.min(1, blended * f_context));
380	}
381	
382	function toRecommendation(score: number, isEscalate: boolean): ScoredAction['recommendation'] {
383	    if (isEscalate) return 'escalate';
384	    if (score >= 0.65) return 'recommend';
385	    if (score >= 0.40) return 'neutral';
386	    return 'avoid';
387	}
388	
389	// ── Main query ────────────────────────────────────────────────
390	async function fetchScoresFromDB(
391	    customerId: string,
392	    contextId: string
393	): Promise<{ scores: ActionScore[]; view_refreshed_at: string | null }> {
394	    const { data, error } = await supabase
395	        .from('mv_action_scores')
396	        .select('*')
397	        .eq('customer_id', customerId)
398	        .eq('context_id', contextId)
399	        .order('weighted_success_rate', { ascending: false });
400	
401	    if (error) throw new Error(`Score query failed: ${error.message}`);
402	
403	    const refreshedAt = data && data.length > 0
404	        ? data[0].view_refreshed_at
405	        : null;
406	
407	    return { scores: (data ?? []) as ActionScore[], view_refreshed_at: refreshedAt };
408	}
409	
410	async function fetchClusterPriors(
411	    customerId: string,
412	    actionIds: string[],
413	): Promise<Map<string, ClusterPrior>> {
414	    const priors = new Map<string, ClusterPrior>();
415	    if (actionIds.length === 0) return priors;
416	
417	    const { data: outcomeRows, error: outcomeError } = await supabase
418	        .from('fact_outcomes')
419	        .select('action_id, semantic_cluster_key, timestamp')
420	        .eq('customer_id', customerId)
421	        .in('action_id', actionIds)
422	        .not('semantic_cluster_key', 'is', null)
423	        .neq('semantic_cluster_key', '')
424	        .order('timestamp', { ascending: false })
425	        .limit(Math.max(actionIds.length * 25, 250));
426	
427	    if (outcomeError || !outcomeRows || outcomeRows.length === 0) {
428	        return priors;
429	    }
430	
431	    const latestClusterByAction = new Map<string, string>();
432	    for (const row of outcomeRows as Array<{ action_id: string; semantic_cluster_key: string | null }>) {
433	        if (!row.semantic_cluster_key) continue;
434	        if (!latestClusterByAction.has(row.action_id)) {
435	            latestClusterByAction.set(row.action_id, row.semantic_cluster_key);
436	        }
437	    }
438	
439	    const uniqueClusters = Array.from(new Set(latestClusterByAction.values()));
440	    if (uniqueClusters.length === 0) return priors;
441	
442	    const { data: clusterRows, error: clusterError } = await supabase
443	        .from('mv_cluster_scores')
444	        .select('semantic_cluster_key, cluster_success_rate, cluster_total_attempts')
445	        .eq('customer_id', customerId)
446	        .in('semantic_cluster_key', uniqueClusters);
447	
448	    if (clusterError || !clusterRows || clusterRows.length === 0) {
449	        return priors;
450	    }
451	
452	    const clusterStats = new Map<string, ClusterPrior>();
453	    for (const row of clusterRows as Array<{
454	        semantic_cluster_key: string;
455	        cluster_success_rate: number | null;
456	        cluster_total_attempts: number | null;
457	    }>) {
458	        const successRate = Math.max(0, Math.min(1, Number(row.cluster_success_rate ?? 0)));
459	        const totalAttempts = Math.max(0, Number(row.cluster_total_attempts ?? 0));
460	        clusterStats.set(row.semantic_cluster_key, {
461	            successRate,
462	            totalAttempts,
463	        });
464	    }
465	
466	    for (const [actionId, clusterKey] of latestClusterByAction.entries()) {
467	        const stats = clusterStats.get(clusterKey);
468	        if (stats) {
469	            priors.set(actionId, stats);
470	        }
471	    }
472	
473	    return priors;
474	}
475	
476	function blendWithClusterPrior(
477	    baseScore: number,
478	    row: ActionScore,
479	    clusterPrior: ClusterPrior | undefined,
480	): number {
481	    if (!clusterPrior) return baseScore;
482	
483	    const sampleCount = Number(row.total_attempts ?? 0);
484	    if (sampleCount >= CLUSTER_PRIOR_LOW_SAMPLE_THRESHOLD) {
485	        return baseScore;
486	    }
487	
488	    const deficitWeight = (CLUSTER_PRIOR_LOW_SAMPLE_THRESHOLD - sampleCount)
489	        / CLUSTER_PRIOR_LOW_SAMPLE_THRESHOLD;
490	    const priorStrength = Math.min(
491	        1,
492	        clusterPrior.totalAttempts / CLUSTER_PRIOR_STRONG_SIGNAL_MIN_SAMPLES,
493	    );
494	    const blendWeight = Math.min(
495	        CLUSTER_PRIOR_MAX_BLEND,
496	        deficitWeight * priorStrength * CLUSTER_PRIOR_MAX_BLEND,
497	    );
498	
499	    const blended = (baseScore * (1 - blendWeight)) + (clusterPrior.successRate * blendWeight);
500	    return Math.max(0, Math.min(1, blended));
501	}
502	
503	// ── Institutional knowledge fallback ─────────────────────────
504	async function fetchInstitutionalFallback(
505	    contextType: string
506	): Promise<ScoredAction[]> {
507	    // JOIN dim_actions so we get real action names, not just IDs
508	    const { data, error } = await supabase
509	        .from('dim_institutional_knowledge')
510	        .select(`
511	            action_id,
512	            avg_success_rate,
513	            sample_count,
514	            context_type,
515	            dim_actions!inner(action_id, action_name, action_category)
516	        `)
517	        .eq('context_type', contextType)
518	        .order('avg_success_rate', { ascending: false });
519	
520	    if (error || !data || data.length === 0) return [];
521	
522	    return data.map((row: any): ScoredAction => ({
523	        action_id: row.action_id,
524	        action_name: row.dim_actions?.action_name ?? row.action_id,
525	        action_category: row.dim_actions?.action_category ?? 'unknown',
526	        composite_score: Math.round((row.avg_success_rate ?? 0) * 10000) / 10000,
527	        confidence: 0,  // no per-customer data yet
528	        trend_delta: null,
529	        trend: 'stable',
530	        total_attempts: row.sample_count ?? 0,
531	        is_cold_start: true,
532	        is_low_sample: (row.sample_count ?? 0) < 3,
533	        recommendation: toRecommendation(row.avg_success_rate ?? 0, false),
534	    }));
535	}
536	
537	// ── Global fallback (Tier 3) ──────────────────────────────────
538	// Used when no context-specific priors exist for the given issue_type.
539	// Queries context_type = 'global' — always non-empty after migration 066.
540	// After this tier, ranked_actions is never empty.
541	async function fetchGlobalFallback(): Promise<ScoredAction[]> {
542	    const { data, error } = await supabase
543	        .from('dim_institutional_knowledge')
544	        .select(`
545	            action_id,
546	            avg_success_rate,
547	            sample_count,
548	            context_type,
549	            dim_actions!inner(action_id, action_name, action_category)
550	        `)
551	        .eq('context_type', 'global')
552	        .order('avg_success_rate', { ascending: false });
553	
554	    if (error || !data || data.length === 0) return [];
555	
556	    return data.map((row: any): ScoredAction => ({
557	        action_id: row.action_id,
558	        action_name: row.dim_actions?.action_name ?? row.action_id,
559	        action_category: row.dim_actions?.action_category ?? 'unknown',
560	        composite_score: Math.round((row.avg_success_rate ?? 0) * 10000) / 10000,
561	        confidence: 0,
562	        trend_delta: null,
563	        trend: 'stable',
564	        total_attempts: row.sample_count ?? 0,
565	        is_cold_start: true,
566	        is_low_sample: false,
567	        recommendation: toRecommendation(row.avg_success_rate ?? 0, false),
568	    }));
569	}
570	
571	// ── Public API ────────────────────────────────────────────────
572	export async function getScores(
573	    customerId: string,
574	    contextId: string,
575	    contextType?: string,
576	    forceRefresh = false,
577	    contextMatch: number | null = null
578	): Promise<ScoringResult> {
579	    const key = cacheKey(customerId, contextId);
580	    const cached = scoreCache.get(key);
581	
582	    // Serve from cache if valid and not forced
583	    if (!forceRefresh && cached && cached.expires_at > Date.now()) {
584	        const top = cached.scores[0];
585	        return {
586	            ranked_actions: cached.scores,
587	            top_action: top,
588	            should_escalate: top?.composite_score < ESCALATION_SCORE,
589	            cold_start: top?.is_cold_start ?? false,
590	            context_id: contextId,
591	            customer_id: customerId,
592	            view_refreshed_at: null,
593	            served_from_cache: true,
594	        };
595	    }
596	
597	    // Fetch from materialized view
598	    const { scores: rawScores, view_refreshed_at } = await fetchScoresFromDB(customerId, contextId);
599	
600	    let scoredActions: ScoredAction[];
601	    let isColdStart = false;
602	
603	    if (rawScores.length === 0 || rawScores.every(r => r.confidence < MIN_CONFIDENCE)) {
604	        isColdStart = true;
605	
606	        // Tier 2: context-specific institutional priors
607	        let fallback = contextType
608	            ? await fetchInstitutionalFallback(contextType)
609	            : [];
610	
611	        // Tier 3: global fallback — ranked_actions is NEVER empty after migration 066
612	        if (fallback.length === 0) {
613	            console.info(
614	                `[scoring] No priors for context_type="${contextType ?? 'none'}". ` +
615	                `Using global fallback.`
616	            );
617	            fallback = await fetchGlobalFallback();
618	        }
619	
620	        scoredActions = fallback;
621	    } else {
622	        const contextLatencyP75 = computeContextLatencyBaselineP75(rawScores);
623	
624	        const lowSampleRows = rawScores.filter(r => (r.total_attempts ?? 0) < 20);
625	        const ipsMap = lowSampleRows.length > 0
626	            ? await withTimeout(
627	                batchFetchIPSSignals(lowSampleRows.map(r => r.action_id), customerId),
628	                2000
629	            ) ?? new Map<string, number>()
630	            : new Map<string, number>();
631	
632	        const clusterPriors = await withTimeout(
633	            fetchClusterPriors(customerId, rawScores.map((row) => row.action_id)),
634	            2000,
635	        ) ?? new Map<string, ClusterPrior>();
636	
637	        scoredActions = rawScores.map((row): ScoredAction => {
638	            const score = computeCompositeScore(
639	                row,
640	                contextMatch,
641	                ipsMap.get(row.action_id) ?? null,
642	                contextLatencyP75,
643	            );
644	            const blendedScore = blendWithClusterPrior(
645	                score,
646	                row,
647	                clusterPriors.get(row.action_id),
648	            );
649	            return {
650	                action_id: row.action_id,
651	                action_name: row.action_name,
652	                action_category: row.action_category,
653	                composite_score: Math.round(blendedScore * 10000) / 10000,
654	                confidence: row.total_attempts < 3 ? Math.min(row.confidence, 0.25) : row.confidence,
655	                trend_delta: row.trend_delta,
656	                trend: trendLabel(row.trend_delta),
657	                total_attempts: row.total_attempts,
658	                is_cold_start: false,
659	                is_low_sample: row.total_attempts < 3,
660	                recommendation: toRecommendation(blendedScore, false),
661	            };
662	        }).sort((a, b) => b.composite_score - a.composite_score);
663	    }
664	
665	    // Store in cache
666	    scoreCache.set(key, { scores: scoredActions, expires_at: Date.now() + CACHE_TTL_MS });
667	    if (scoreCache.size > MAX_CACHE_ENTRIES) {
668	        const oldestKey = scoreCache.keys().next().value as string | undefined;
669	        if (oldestKey) scoreCache.delete(oldestKey);
670	    }
671	
672	    const top = scoredActions[0] ?? null;
673	
674	    return {
675	        ranked_actions: scoredActions,
676	        top_action: top,
677	        should_escalate: !top || top.composite_score < ESCALATION_SCORE,
678	        cold_start: isColdStart,
679	        context_id: contextId,
680	        customer_id: customerId,
681	        view_refreshed_at: view_refreshed_at,
682	        served_from_cache: false,
683	    };
684	}
685	
686	// Export constants for tests
687	export { MIN_CONFIDENCE, ESCALATION_SCORE, W_SUCCESS, W_CONF, W_TREND, W_SALIENCE, W_RECENCY, W_LATENCY };
688	
689	/**
690	 * Compute the effective score for an outcome.
691	 * If outcome_score is provided and valid (0.0–1.0), use it.
692	 * Otherwise fall back to binary: success=1.0, failure=0.0.
693	 *
694	 * This mirrors the DB-level COALESCE(outcome_score, success::FLOAT)
695	 * used in mv_action_scores, but for application-level logic.
696	 */
697	export function computeEffectiveScore(
698	    success: boolean,
699	    outcomeScore?: number
700	): number {
701	    if (outcomeScore !== undefined && outcomeScore >= 0.0 && outcomeScore <= 1.0) {
702	        return outcomeScore;
703	    }
704	    return success ? 1.0 : 0.0;
705	}
