/**
 * Layerinfinite — lib/scoring.ts
 * ══════════════════════════════════════════════════════════════
 * 6-Factor Composite Scoring Engine
 * ══════════════════════════════════════════════════════════════
 *
 * FORMULA:
 *   composite_score = (
 *     w_success  * weighted_success_rate  +
 *     w_conf     * confidence             +
 *     w_trend    * trend_factor           +
 *     w_salience * salience_factor        +
 *     w_recency  * recency_factor         +
 *     w_latency  * latency_factor
 *   )
 *
 * Weights sum to 1.0. All inputs are normalised to [0, 1].
 *
 * Salience = importance weight of this action (from database).
 * Cold-start (confidence < MIN_CONFIDENCE): returns institutional priors.
 *
 * IN-MEMORY CACHE (5 min TTL):
 *   One entry per (action_id, context_id, customer_id).
 *   Refreshed on scoring-engine cron or on-demand.
 *   Falls back to DB query on cache miss.
 */

import { supabase, ActionScore } from './supabase.js';

// ── Weights ──────────────────────────────────────────────────
const W_SUCCESS = 0.40;  // primary driver
const W_CONF = 0.20;  // uncertainty penalty
const W_TREND = 0.20;  // directional momentum
const W_SALIENCE = 0.10;  // action importance
const W_RECENCY = 0.05;  // freshness bonus
const W_LATENCY = 0.05;  // response-time quality signal

// Bayesian (Laplace) smoothing priors for composite score calculation.
// Used in computeCompositeScore(): (successes + α) / (total + α + β).
// NOTE: These are NOT used in updateAgentTrust() (outcome-orchestrator.ts),
// which uses exponential smoothing independently.
export const PRIOR_ALPHA = 1.0;  // Laplace prior successes (neutral = 1)
export const PRIOR_BETA = 1.0;  // Laplace prior failures  (neutral = 1)

// ── Thresholds ───────────────────────────────────────────────
const MIN_CONFIDENCE = 0.15;  // below this → cold-start fallback (was 0.30; lowered so 2+ outcomes can differentiate)
const ESCALATION_SCORE = 0.20;  // below this → escalate_human
const CACHE_TTL_MS = 5 * 60 * 1000;  // 5 minutes
// LRU eviction: 1000 entries × ~2KB avg = ~2MB max resident cache size.
// V8 Map preserves insertion order; oldest key = first key in iterator.
// At 1000 entries, single-deletion eviction keeps memory bounded without
// a full LRU linked list implementation.
const MAX_CACHE_ENTRIES = 1000;
const IPS_DECISION_CHUNK_SIZE = 50;
const CLUSTER_PRIOR_MAX_BLEND = 0.15;
const CLUSTER_PRIOR_LOW_SAMPLE_THRESHOLD = 10;
const CLUSTER_PRIOR_STRONG_SIGNAL_MIN_SAMPLES = 50;

function withTimeout<T>(promise: Promise<T>, ms: number): Promise<T | null> {
    return Promise.race([
        promise,
        new Promise<null>((resolve) => setTimeout(() => resolve(null), ms)),
    ]) as Promise<T | null>;
}

// ── In-Memory Score Cache ─────────────────────────────────────
interface CacheEntry {
    scores: ScoredAction[];
    expires_at: number;
}

const scoreCache = new Map<string, CacheEntry>();

// Evict expired entries every 5 minutes
const CLEANUP_INTERVAL_MS = 5 * 60_000;
setInterval(() => {
    const now = Date.now();
    let evicted = 0;
    for (const [key, entry] of scoreCache.entries()) {
        if (entry.expires_at < now) {
            scoreCache.delete(key);
            evicted++;
        }
    }
    if (evicted > 0) {
        console.info(`[cache-cleanup] Evicted ${evicted} expired entries from scoreCache`);
    }
}, CLEANUP_INTERVAL_MS).unref();

setInterval(() => {
    if (scoreCache.size > 0 && process.env['NODE_ENV'] !== 'production') {
        console.debug(`[cache-size] scoreCache: ${scoreCache.size} entries`);
    }
}, 15 * 60_000).unref();

function cacheKey(customerId: string, contextId: string): string {
    return `${customerId}:${contextId}`;
}

/**
 * Call this after any successful outcome write for (customerId, contextId).
 * Ensures the next getScores() call fetches fresh data from mv_action_scores
 * instead of serving a cached cold-start fallback.
 */
export function invalidateCache(customerId?: string, contextId?: string): void {
    if (customerId && contextId) {
        scoreCache.delete(cacheKey(customerId, contextId));
    } else {
        scoreCache.clear();
    }
}

/**
 * Returns the cached composite score for a specific action in a context.
 * Used by log-outcome.ts for salience sampling:
 *   if (score > 0.9 && success) → salience = 0.1 (sampled down)
 * Returns null on cache miss (caller defaults to salience=1.0).
 */
export function getCachedScore(
    actionId: string,
    contextId: string,
    customerId: string
): number | null {
    // Scan the cache for this customer+context
    const key = cacheKey(customerId, contextId);
    const cached = scoreCache.get(key);
    if (!cached || cached.expires_at <= Date.now()) return null;

    const match = cached.scores.find(s => s.action_id === actionId);
    return match ? match.composite_score : null;
}

// ── Scoring types ─────────────────────────────────────────────
export type TrendLabel = 'stable' | 'improving' | 'degrading' | 'critical';

export function trendLabel(trendDelta: number | null): TrendLabel {
    if (trendDelta === null) return 'stable';
    if (trendDelta <= -0.15) return 'critical';
    if (trendDelta < -0.05) return 'degrading';
    if (trendDelta > 0.05) return 'improving';
    return 'stable';
}

export interface ScoredAction {
    action_id: string;
    action_name: string;
    action_category: string;
    composite_score: number;
    confidence: number;
    trend_delta: number | null;
    trend: TrendLabel;
    total_attempts: number;
    is_cold_start: boolean;
    is_low_sample: boolean;
    recommendation: 'recommend' | 'neutral' | 'avoid' | 'escalate';
}

export interface ScoringResult {
    ranked_actions: ScoredAction[];
    top_action: ScoredAction;
    should_escalate: boolean;
    cold_start: boolean;
    context_id: string;
    customer_id: string;
    view_refreshed_at: string | null;
    served_from_cache: boolean;
}

interface IPSBatchRow {
    unchosen_action_id: string | null;
    counterfactual_est: number | null;
    ips_weight: number | null;
    created_at: string | null;
}

interface ClusterPrior {
    successRate: number;
    totalAttempts: number;
}

function percentile(sortedValues: number[], q: number): number | null {
    if (sortedValues.length === 0) return null;
    if (sortedValues.length === 1) return sortedValues[0] ?? null;

    const clampedQ = Math.max(0, Math.min(1, q));
    const idx = (sortedValues.length - 1) * clampedQ;
    const lo = Math.floor(idx);
    const hi = Math.ceil(idx);
    if (lo === hi) return sortedValues[lo] ?? null;

    const loVal = sortedValues[lo] ?? 0;
    const hiVal = sortedValues[hi] ?? loVal;
    const frac = idx - lo;
    return loVal + (hiVal - loVal) * frac;
}

function computeContextLatencyBaselineP75(rows: ActionScore[]): number | null {
    const latencies = rows
        .map((row) => row.avg_response_ms)
        .filter((v): v is number => typeof v === 'number' && Number.isFinite(v) && v > 0)
        .sort((a, b) => a - b);

    return percentile(latencies, 0.75);
}

function computeLatencyFactor(avgResponseMs: number | null | undefined, p75ResponseMs: number | null): number {
    if (typeof avgResponseMs !== 'number' || !Number.isFinite(avgResponseMs) || avgResponseMs <= 0) {
        return 0.5;
    }
    if (typeof p75ResponseMs !== 'number' || !Number.isFinite(p75ResponseMs) || p75ResponseMs <= 0) {
        return 0.5;
    }

    // ratio=1.0 => neutral 0.5; faster actions score above neutral, slower actions below.
    const ratio = avgResponseMs / p75ResponseMs;
    const clamped = Math.max(0, Math.min(2, ratio));
    return Math.max(0, Math.min(1, 1 - clamped / 2));
}

async function batchFetchIPSSignals(
    actionIds: string[],
    customerId: string
): Promise<Map<string, number>> {
    const uniqueActionIds = [...new Set(actionIds.filter(Boolean))];
    if (uniqueActionIds.length === 0) return new Map<string, number>();

    // Step 1: scope decisions to the tenant via agent ownership.
    const { data: decisions, error: decisionsError } = await supabase
        .from('fact_decisions')
        .select('id, dim_agents!inner(customer_id)')
        .eq('dim_agents.customer_id', customerId)
        .order('created_at', { ascending: false })
        .limit(200);

    if (decisionsError) {
        console.warn('[scoring] IPS decision scope lookup failed:', decisionsError.message);
        return new Map<string, number>();
    }

    const decisionIds = (decisions ?? []).map((d: any) => d.id).filter(Boolean);
    if (decisionIds.length === 0) return new Map<string, number>();

    const chunks: string[][] = [];
    for (let i = 0; i < decisionIds.length; i += IPS_DECISION_CHUNK_SIZE) {
        chunks.push(decisionIds.slice(i, i + IPS_DECISION_CHUNK_SIZE));
    }

    const chunkResults = await Promise.all(chunks.map(async (chunk, i) => {
        const { data, error } = await supabase
            .from('fact_outcome_counterfactuals')
            .select('unchosen_action_id, counterfactual_est, ips_weight, created_at')
            .in('decision_id', chunk)
            .in('unchosen_action_id', uniqueActionIds)
            .order('created_at', { ascending: false })
            .limit(5 * uniqueActionIds.length);

        if (error) {
            console.warn(
                `[scoring] IPS batch query failed (chunk ${i}):`,
                error.message,
                '| chunk_size:',
                chunk.length,
                '| action_count:',
                uniqueActionIds.length
            );
            return [] as IPSBatchRow[];
        }

        return (data ?? []) as IPSBatchRow[];
    }));

    const deduped = new Map<string, IPSBatchRow>();
    for (const row of chunkResults.flat()) {
        if (!row.unchosen_action_id || !row.created_at) continue;
        const dedupeKey = `${row.unchosen_action_id}:${row.created_at}`;
        if (!deduped.has(dedupeKey)) {
            deduped.set(dedupeKey, row);
        }
    }

    if (deduped.size === 0) return new Map<string, number>();

    const grouped = new Map<string, IPSBatchRow[]>();
    for (const row of deduped.values()) {
        const actionId = row.unchosen_action_id;
        if (!actionId) continue;
        const existing = grouped.get(actionId) ?? [];
        existing.push(row);
        grouped.set(actionId, existing);
    }

    const signals = new Map<string, number>();
    for (const actionId of uniqueActionIds) {
        const rows = (grouped.get(actionId) ?? [])
            .sort(
                (a, b) => new Date(b.created_at ?? 0).getTime() - new Date(a.created_at ?? 0).getTime()
            )
            .slice(0, 5);

        if (rows.length === 0) continue;

        const avgEstimate = rows.reduce((sum, r) => sum + (r.counterfactual_est ?? 0), 0) / rows.length;
        const avgWeight = rows.reduce((sum, r) => sum + (r.ips_weight ?? 0), 0) / rows.length;
        const blendedSignal = Math.max(0, Math.min(1, avgEstimate * avgWeight));
        signals.set(actionId, blendedSignal);
    }

    return signals;
}

// ── 6-Factor scoring formula ─────────────────────────────────
/**
 * @param contextMatch — cosine similarity from context-embed.ts.
 *   null means exact match (fallback) → treated as 1.0.
 */
export function computeCompositeScore(
    row: ActionScore,
    contextMatch: number | null = null,
    ipsSignal: number | null = null,
    p75ResponseMs: number | null = null,
): number {
    // Factor 1: Weighted success rate (primary)
    // Applied Bayesian smoothing (Laplace / Beta distribution prior):
    const rawSuccessRate = row.weighted_success_rate ?? row.raw_success_rate ?? 0;
    const n = row.total_attempts ?? 0;

    // Bayesian smoothed rate:
    // (successes + alpha) / (total + alpha + beta)
    const f_success = (rawSuccessRate * n + PRIOR_ALPHA) / (n + PRIOR_ALPHA + PRIOR_BETA);

    // Factor 2: Confidence (Wilson-style: n/(n+10))
    const f_conf = row.confidence ?? 0;

    // Factor 3: Trend delta → normalised to [0,1]
    const rawTrend = row.trend_delta ?? 0;
    const f_trend = Math.max(0, Math.min(1, (rawTrend + 0.5)));

    // Factor 4: Salience — use actual salience_score from fact_outcomes
    // if available on the row. Defaults to 1.0 (neutral) if not present.
    // mv_action_scores exposes avg_salience_score computed from fact_outcomes.
    // If the column is null (old rows), fall back to 1.0 so behaviour is
    // unchanged for existing data.
    const rawSalience = (row as any).avg_salience_score;
    const f_salience = (rawSalience !== null && rawSalience !== undefined)
        ? Math.max(0, Math.min(1, Number(rawSalience)))
        : 1.0;

    // Factor 5: Recency — bonus if last outcome < 24h ago
    let f_recency = 0.5;  // neutral default
    if (row.last_outcome_at) {
        const ageHours = (Date.now() - new Date(row.last_outcome_at).getTime()) / 3_600_000;
        f_recency = Math.max(0, Math.min(1, 1 - (ageHours / 168)));  // decay over 7 days
    }

    // Factor 6: Latency — compare action's avg response time to context baseline p75.
    const f_latency = computeLatencyFactor(row.avg_response_ms, p75ResponseMs);

    // Context match factor: null → 1.0 (exact match assumed)
    const f_context = contextMatch ?? 1.0;

    const baseScore = (
        W_SUCCESS * f_success +
        W_CONF * f_conf +
        W_TREND * f_trend +
        W_SALIENCE * f_salience +
        W_RECENCY * f_recency +
        W_LATENCY * f_latency
    );

    const sampleCount = row.total_attempts ?? 0;
    if (sampleCount >= 20 || ipsSignal === null) {
        return Math.max(0, Math.min(1, baseScore * f_context));
    }

    const blendWeight = Math.min(0.10, ((20 - sampleCount) / 20) * 0.10);
    const blended = baseScore * (1 - blendWeight) + ipsSignal * blendWeight;

    // Final clamp: composite_score must ALWAYS be in [0, 1]
    return Math.max(0, Math.min(1, blended * f_context));
}

function toRecommendation(score: number, isEscalate: boolean): ScoredAction['recommendation'] {
    if (isEscalate) return 'escalate';
    if (score >= 0.65) return 'recommend';
    if (score >= 0.40) return 'neutral';
    return 'avoid';
}

// ── Main query ────────────────────────────────────────────────
async function fetchScoresFromDB(
    customerId: string,
    contextId: string
): Promise<{ scores: ActionScore[]; view_refreshed_at: string | null }> {
    const { data, error } = await supabase
        .from('mv_action_scores')
        .select('*')
        .eq('customer_id', customerId)
        .eq('context_id', contextId)
        .order('weighted_success_rate', { ascending: false });

    if (error) throw new Error(`Score query failed: ${error.message}`);

    const refreshedAt = data && data.length > 0
        ? data[0].view_refreshed_at
        : null;

    return { scores: (data ?? []) as ActionScore[], view_refreshed_at: refreshedAt };
}

async function fetchClusterPriors(
    customerId: string,
    actionIds: string[],
): Promise<Map<string, ClusterPrior>> {
    const priors = new Map<string, ClusterPrior>();
    if (actionIds.length === 0) return priors;

    const { data: outcomeRows, error: outcomeError } = await supabase
        .from('fact_outcomes')
        .select('action_id, semantic_cluster_key, timestamp')
        .eq('customer_id', customerId)
        .in('action_id', actionIds)
        .not('semantic_cluster_key', 'is', null)
        .neq('semantic_cluster_key', '')
        .order('timestamp', { ascending: false })
        .limit(Math.max(actionIds.length * 25, 250));

    if (outcomeError || !outcomeRows || outcomeRows.length === 0) {
        return priors;
    }

    const latestClusterByAction = new Map<string, string>();
    for (const row of outcomeRows as Array<{ action_id: string; semantic_cluster_key: string | null }>) {
        if (!row.semantic_cluster_key) continue;
        if (!latestClusterByAction.has(row.action_id)) {
            latestClusterByAction.set(row.action_id, row.semantic_cluster_key);
        }
    }

    const uniqueClusters = Array.from(new Set(latestClusterByAction.values()));
    if (uniqueClusters.length === 0) return priors;

    const { data: clusterRows, error: clusterError } = await supabase
        .from('mv_cluster_scores')
        .select('semantic_cluster_key, cluster_success_rate, cluster_total_attempts')
        .eq('customer_id', customerId)
        .in('semantic_cluster_key', uniqueClusters);

    if (clusterError || !clusterRows || clusterRows.length === 0) {
        return priors;
    }

    const clusterStats = new Map<string, ClusterPrior>();
    for (const row of clusterRows as Array<{
        semantic_cluster_key: string;
        cluster_success_rate: number | null;
        cluster_total_attempts: number | null;
    }>) {
        const successRate = Math.max(0, Math.min(1, Number(row.cluster_success_rate ?? 0)));
        const totalAttempts = Math.max(0, Number(row.cluster_total_attempts ?? 0));
        clusterStats.set(row.semantic_cluster_key, {
            successRate,
            totalAttempts,
        });
    }

    for (const [actionId, clusterKey] of latestClusterByAction.entries()) {
        const stats = clusterStats.get(clusterKey);
        if (stats) {
            priors.set(actionId, stats);
        }
    }

    return priors;
}

function blendWithClusterPrior(
    baseScore: number,
    row: ActionScore,
    clusterPrior: ClusterPrior | undefined,
): number {
    if (!clusterPrior) return baseScore;

    const sampleCount = Number(row.total_attempts ?? 0);
    if (sampleCount >= CLUSTER_PRIOR_LOW_SAMPLE_THRESHOLD) {
        return baseScore;
    }

    const deficitWeight = (CLUSTER_PRIOR_LOW_SAMPLE_THRESHOLD - sampleCount)
        / CLUSTER_PRIOR_LOW_SAMPLE_THRESHOLD;
    const priorStrength = Math.min(
        1,
        clusterPrior.totalAttempts / CLUSTER_PRIOR_STRONG_SIGNAL_MIN_SAMPLES,
    );
    const blendWeight = Math.min(
        CLUSTER_PRIOR_MAX_BLEND,
        deficitWeight * priorStrength * CLUSTER_PRIOR_MAX_BLEND,
    );

    const blended = (baseScore * (1 - blendWeight)) + (clusterPrior.successRate * blendWeight);
    return Math.max(0, Math.min(1, blended));
}

// ── Institutional knowledge fallback ─────────────────────────
async function fetchInstitutionalFallback(
    contextType: string
): Promise<ScoredAction[]> {
    // JOIN dim_actions so we get real action names, not just IDs
    const { data, error } = await supabase
        .from('dim_institutional_knowledge')
        .select(`
            action_id,
            avg_success_rate,
            sample_count,
            context_type,
            dim_actions!inner(action_id, action_name, action_category)
        `)
        .eq('context_type', contextType)
        .order('avg_success_rate', { ascending: false });

    if (error || !data || data.length === 0) return [];

    return data.map((row: any): ScoredAction => ({
        action_id: row.action_id,
        action_name: row.dim_actions?.action_name ?? row.action_id,
        action_category: row.dim_actions?.action_category ?? 'unknown',
        composite_score: Math.round((row.avg_success_rate ?? 0) * 10000) / 10000,
        confidence: 0,  // no per-customer data yet
        trend_delta: null,
        trend: 'stable',
        total_attempts: row.sample_count ?? 0,
        is_cold_start: true,
        is_low_sample: (row.sample_count ?? 0) < 3,
        recommendation: toRecommendation(row.avg_success_rate ?? 0, false),
    }));
}

// ── Global fallback (Tier 3) ──────────────────────────────────
// Used when no context-specific priors exist for the given issue_type.
// Queries context_type = 'global' — always non-empty after migration 066.
// After this tier, ranked_actions is never empty.
async function fetchGlobalFallback(): Promise<ScoredAction[]> {
    const { data, error } = await supabase
        .from('dim_institutional_knowledge')
        .select(`
            action_id,
            avg_success_rate,
            sample_count,
            context_type,
            dim_actions!inner(action_id, action_name, action_category)
        `)
        .eq('context_type', 'global')
        .order('avg_success_rate', { ascending: false });

    if (error || !data || data.length === 0) return [];

    return data.map((row: any): ScoredAction => ({
        action_id: row.action_id,
        action_name: row.dim_actions?.action_name ?? row.action_id,
        action_category: row.dim_actions?.action_category ?? 'unknown',
        composite_score: Math.round((row.avg_success_rate ?? 0) * 10000) / 10000,
        confidence: 0,
        trend_delta: null,
        trend: 'stable',
        total_attempts: row.sample_count ?? 0,
        is_cold_start: true,
        is_low_sample: false,
        recommendation: toRecommendation(row.avg_success_rate ?? 0, false),
    }));
}

// ── Public API ────────────────────────────────────────────────
export async function getScores(
    customerId: string,
    contextId: string,
    contextType?: string,
    forceRefresh = false,
    contextMatch: number | null = null
): Promise<ScoringResult> {
    const key = cacheKey(customerId, contextId);
    const cached = scoreCache.get(key);

    // Serve from cache if valid and not forced
    if (!forceRefresh && cached && cached.expires_at > Date.now()) {
        const top = cached.scores[0];
        return {
            ranked_actions: cached.scores,
            top_action: top,
            should_escalate: top?.composite_score < ESCALATION_SCORE,
            cold_start: top?.is_cold_start ?? false,
            context_id: contextId,
            customer_id: customerId,
            view_refreshed_at: null,
            served_from_cache: true,
        };
    }

    // Fetch from materialized view
    const { scores: rawScores, view_refreshed_at } = await fetchScoresFromDB(customerId, contextId);

    let scoredActions: ScoredAction[];
    let isColdStart = false;

    if (rawScores.length === 0 || rawScores.every(r => r.confidence < MIN_CONFIDENCE)) {
        isColdStart = true;

        // Tier 2: context-specific institutional priors
        let fallback = contextType
            ? await fetchInstitutionalFallback(contextType)
            : [];

        // Tier 3: global fallback — ranked_actions is NEVER empty after migration 066
        if (fallback.length === 0) {
            console.info(
                `[scoring] No priors for context_type="${contextType ?? 'none'}". ` +
                `Using global fallback.`
            );
            fallback = await fetchGlobalFallback();
        }

        scoredActions = fallback;
    } else {
        const contextLatencyP75 = computeContextLatencyBaselineP75(rawScores);

        const lowSampleRows = rawScores.filter(r => (r.total_attempts ?? 0) < 20);
        const ipsMap = lowSampleRows.length > 0
            ? await withTimeout(
                batchFetchIPSSignals(lowSampleRows.map(r => r.action_id), customerId),
                2000
            ) ?? new Map<string, number>()
            : new Map<string, number>();

        const clusterPriors = await withTimeout(
            fetchClusterPriors(customerId, rawScores.map((row) => row.action_id)),
            2000,
        ) ?? new Map<string, ClusterPrior>();

        scoredActions = rawScores.map((row): ScoredAction => {
            const score = computeCompositeScore(
                row,
                contextMatch,
                ipsMap.get(row.action_id) ?? null,
                contextLatencyP75,
            );
            const blendedScore = blendWithClusterPrior(
                score,
                row,
                clusterPriors.get(row.action_id),
            );
            return {
                action_id: row.action_id,
                action_name: row.action_name,
                action_category: row.action_category,
                composite_score: Math.round(blendedScore * 10000) / 10000,
                confidence: row.total_attempts < 3 ? Math.min(row.confidence, 0.25) : row.confidence,
                trend_delta: row.trend_delta,
                trend: trendLabel(row.trend_delta),
                total_attempts: row.total_attempts,
                is_cold_start: false,
                is_low_sample: row.total_attempts < 3,
                recommendation: toRecommendation(blendedScore, false),
            };
        }).sort((a, b) => b.composite_score - a.composite_score);
    }

    // Store in cache
    scoreCache.set(key, { scores: scoredActions, expires_at: Date.now() + CACHE_TTL_MS });
    if (scoreCache.size > MAX_CACHE_ENTRIES) {
        const oldestKey = scoreCache.keys().next().value as string | undefined;
        if (oldestKey) scoreCache.delete(oldestKey);
    }

    const top = scoredActions[0] ?? null;

    return {
        ranked_actions: scoredActions,
        top_action: top,
        should_escalate: !top || top.composite_score < ESCALATION_SCORE,
        cold_start: isColdStart,
        context_id: contextId,
        customer_id: customerId,
        view_refreshed_at: view_refreshed_at,
        served_from_cache: false,
    };
}

// Export constants for tests
export { MIN_CONFIDENCE, ESCALATION_SCORE, W_SUCCESS, W_CONF, W_TREND, W_SALIENCE, W_RECENCY, W_LATENCY };

/**
 * Compute the effective score for an outcome.
 * If outcome_score is provided and valid (0.0–1.0), use it.
 * Otherwise fall back to binary: success=1.0, failure=0.0.
 *
 * This mirrors the DB-level COALESCE(outcome_score, success::FLOAT)
 * used in mv_action_scores, but for application-level logic.
 */
export function computeEffectiveScore(
    success: boolean,
    outcomeScore?: number
): number {
    if (outcomeScore !== undefined && outcomeScore >= 0.0 && outcomeScore <= 1.0) {
        return outcomeScore;
    }
    return success ? 1.0 : 0.0;
}

