26	    if (!value) return fallback;
27	    const normalized = value.trim().toLowerCase();
28	    if (['1', 'true', 'yes', 'on'].includes(normalized)) return true;
29	    if (['0', 'false', 'no', 'off'].includes(normalized)) return false;
30	    return fallback;
31	}
